const ethers = require('ethers');
const Web3 = require('web3');

class EthereumService {
  constructor(providerUrl, privateKey) {
    this.providerUrl = providerUrl;
    this.privateKey = privateKey;
    this.web3 = new Web3(providerUrl);
    this.wallet = new ethers.Wallet(privateKey, this.web3.provider);
  }

  async getBalance(address) {
    try {
      const balance = await this.web3.eth.getBalance(address);
      return ethers.utils.formatEther(balance);
    } catch (error) {
      throw new Error(`Failed to get balance: ${error.message}`);
    }
  }

  async sendETH(toAddress, amount) {
    try {
      const amountInWei = ethers.utils.parseEther(amount);
      const nonce = await this.web3.eth.getTransactionCount(this.wallet.address);
      
      const transaction = {
        to: toAddress,
        value: amountInWei,
        nonce: nonce,
        gasLimit: 21000,
        gasPrice: await this.web3.eth.getGasPrice()
      };

      const signedTx = await this.wallet.signTransaction(transaction);
      const receipt = await this.web3.eth.sendSignedTransaction(signedTx);
      
      return receipt;
    } catch (error) {
      throw new Error(`Failed to send ETH: ${error.message}`);
    }
  }

  async callContractMethod(contractAddress, abi, methodName, args = [], value = '0') {
    try {
      const contract = new this.web3.eth.Contract(abi, contractAddress);
      const nonce = await this.web3.eth.getTransactionCount(this.wallet.address);
      
      const method = contract.methods[methodName](...args);
      const gasEstimate = await method.estimateGas({ from: this.wallet.address, value });
      
      const transaction = {
        to: contractAddress,
        data: method.encodeABI(),
        value: ethers.utils.parseEther(value),
        nonce: nonce,
        gasLimit: Math.floor(gasEstimate * 1.2),
        gasPrice: await this.web3.eth.getGasPrice()
      };

      const signedTx = await this.wallet.signTransaction(transaction);
      const receipt = await this.web3.eth.sendSignedTransaction(signedTx);
      
      return receipt;
    } catch (error) {
      throw new Error(`Failed to call contract method: ${error.message}`);
    }
  }

  async deployContract(abi, bytecode, args = []) {
    try {
      const contractFactory = new this.web3.eth.Contract(abi);
      const nonce = await this.web3.eth.getTransactionCount(this.wallet.address);
      
      const deployTx = contractFactory.deploy({
        data: bytecode,
        arguments: args
      });
      
      const gasEstimate = await deployTx.estimateGas({ from: this.wallet.address });
      
      const transaction = {
        data: deployTx.encodeABI(),
        nonce: nonce,
        gasLimit: Math.floor(gasEstimate * 1.2),
        gasPrice: await this.web3.eth.getGasPrice()
      };

      const signedTx = await this.wallet.signTransaction(transaction);
      const receipt = await this.web3.eth.sendSignedTransaction(signedTx);
      
      return receipt;
    } catch (error) {
      throw new Error(`Failed to deploy contract: ${error.message}`);
    }
  }

  async getTransactionReceipt(txHash) {
    try {
      const receipt = await this.web3.eth.getTransactionReceipt(txHash);
      return receipt;
    } catch (error) {
      throw new Error(`Failed to get transaction receipt: ${error.message}`);
    }
  }

  async getTransactionCount(address) {
    try {
      const count = await this.web3.eth.getTransactionCount(address);
      return count;
    } catch (error) {
      throw new Error(`Failed to get transaction count: ${error.message}`);
    }
  }

  async estimateGas(contractAddress, abi, methodName, args = []) {
    try {
      const contract = new this.web3.eth.Contract(abi, contractAddress);
      const method = contract.methods[methodName](...args);
      const gasEstimate = await method.estimateGas({ from: this.wallet.address });
      return gasEstimate;
    } catch (error) {
      throw new Error(`Failed to estimate gas: ${error.message}`);
    }
  }

  async getContractBalance(contractAddress) {
    try {
      const balance = await this.web3.eth.getBalance(contractAddress);
      return ethers.utils.formatEther(balance);
    } catch (error) {
      throw new Error(`Failed to get contract balance: ${error.message}`);
    }
  }

  async validateAddress(address) {
    try {
      return this.web3.utils.isAddress(address);
    } catch (error) {
      throw new Error(`Failed to validate address: ${error.message}`);
    }
  }

  async getNetwork() {
    try {
      const network = await this.web3.eth.net.getNetworkType();
      return network;
    } catch (error) {
      throw new Error(`Failed to get network: ${error.message}`);
    }
  }
}

module.exports = EthereumService;